// Power Query M equivalent — also generated for Fabric Dataflow Gen2
// This block shows the M script view of the same transformations
// Source: bronze.customers
// All transforms above map 1:1 to Power Query steps

let
  Source = Lakehouse.Contents("FastaLakehouse"){[Schema="bronze",Item="customers"]}[Data],
  RemovedDuplicates = Table.Distinct(Source, {"customer_id"}),
  TrimmedNames = Table.TransformColumns(RemovedDuplicates, {
    {"first_name", Text.Proper},
    {"last_name", Text.Proper}
  }),
  ParsedDOB = Table.TransformColumns(TrimmedNames, {
    {"date_of_birth", each
      let
        fmts = {"yyyy-MM-dd", "dd/MM/yyyy", "MM-dd-yyyy", "dd MMM yyyy", "yyyyMMdd"},
        parsed = List.First(List.Select(List.Transform(fmts, (f) => try Date.FromText(_, [Format=f]) otherwise null), (v) => v <> null))
      in parsed,
      type date
    }
  }),
  AgeBand = Table.AddColumn(ParsedDOB, "age_band",
    each if [date_of_birth] = null then "Unknown"
    else let
      age = Duration.TotalDays(DateTime.Date(DateTime.LocalNow()) - [date_of_birth]) / 365.25
    in
      if age >= 18 and age < 25 then "18-24"
      else if age >= 25 and age < 35 then "25-34"
      else if age >= 35 and age < 45 then "35-44"
      else if age >= 45 and age < 55 then "45-54"
      else "55+"
  ),
  GenderStd = Table.AddColumn(AgeBand, "gender_std",
    each if Text.Upper([gender]) = "M" or Text.Upper([gender]) = "MALE" then "Male"
    else if Text.Upper([gender]) = "F" or Text.Upper([gender]) = "FEMALE" then "Female"
    else if Text.Upper([gender]) = "NON-BINARY" then "Non-binary"
    else "Unknown"
  ),
  CleanIncome = Table.ReplaceValue(AgeBand, each [net_income_zar],
    each if [net_income_zar] < 0 then null else [net_income_zar],
    Replacer.ReplaceValue, {"net_income_zar"}
  ),
  DQFlags = Table.AddColumn(CleanIncome, "dq_any_flag",
    each Number.From([date_of_birth] = null or [net_income_zar] = null or [province] = null)
  ),
  AddLoadTs = Table.AddColumn(DQFlags, "_silver_loaded_at", each DateTime.LocalNow())
in
  AddLoadTs
